struct inode* locate(struct inode* cur, char* path[]) {
    struct inode* current = cur;
    int i = 0;
    
    while (path[i] != NULL) {
        struct inode* next = find(current->dir, path[i]);
        
        if (next == NULL) {
            unlock(current);
            return NULL;
        }
        
        lock(next);
        unlock(current);
        current = next;
        i++;
    }
    
    return current;
}

char** calculate(char* srcpath[], char* dstpath[]) {
    char** result = malloc_path(0);
    int len = 0;
    char** src = srcpath;
    char** dst = dstpath;
    
    while (*src != NULL && *dst != NULL) {
        if (strcmp(*src, *dst) != 0) {
            break;
        }
        result = realloc(result, sizeof(char*) * (len + 1));
        result[len] = malloc_string(*src);
        len++;
        src++;
        dst++;
    }
    result = realloc(result, sizeof(char*) * (len + 1));
    result[len] = NULL;
    
    return result;
}

int getlen(char* path[]) {
    int len = 0;
    while (path[len] != NULL) {
        len++;
    }
    return len;
}